package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsNull() throws Exception {
        // Create CSVFormat instance with escapeCharacter null using DEFAULT
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set the private final field escapeCharacter to null
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);

        // Remove final modifier from field (only necessary in some JVMs, but safe)
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(escapeCharacterField, escapeCharacterField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        escapeCharacterField.set(format, null);

        assertFalse(format.isEscapeCharacterSet(), "Escape character should not be set when null");
    }

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsSet() throws Exception {
        // Create CSVFormat instance with escapeCharacter set to BACKSLASH using DEFAULT
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to set the private final field escapeCharacter to '\\'
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);

        // Remove final modifier from field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(escapeCharacterField, escapeCharacterField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        escapeCharacterField.set(format, '\\');

        assertTrue(format.isEscapeCharacterSet(), "Escape character should be set when non-null");
    }
}
